import{bQ as t,aL as a,u as i,G as e}from"./chunks/framework.D06dwy5q.js";const r=JSON.parse('{"title":"tmux 会话管理","description":"","frontmatter":{},"headers":[],"relativePath":"03.远程运维/03-tmux会话管理.md","filePath":"03.远程运维/03-tmux会话管理.md","lastUpdated":null}'),n={name:"03.远程运维/03-tmux会话管理.md"};function p(d,s,l,h,o,c){return a(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="tmux-会话管理" tabindex="-1">tmux 会话管理 <a class="header-anchor" href="#tmux-会话管理" aria-label="Permalink to &quot;tmux 会话管理&quot;">​</a></h1><p>在远程服务器上执行长时间任务时，SSH 连接随时可能意外断开——网络波动、笔记本合盖休眠、WiFi 切换、VPN 超时。普通 shell 里的前台进程在 SSH 断开后会收到 SIGHUP 信号，往往直接被终止。tmux 把会话留在服务器上，SSH 断了、任务还在跑，重连后可以恢复现场。</p><h2 id="一、tmux-的位置在哪" tabindex="-1">一、tmux 的位置在哪 <a class="header-anchor" href="#一、tmux-的位置在哪" aria-label="Permalink to &quot;一、tmux 的位置在哪&quot;">​</a></h2><p>SSH 是客户端到服务器的一条加密通道。这条通道断了，里面的 shell 也就没了。tmux 在服务器上启动一个独立的会话进程，SSH 只是&quot;借来看一眼&quot;——断开不伤害 tmux，tmux 里的程序照跑。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本地终端 -&gt; SSH -&gt; 服务器 -&gt; tmux session -&gt; shell / 命令 / 程序</span></span></code></pre></div><p>也就是说，tmux 跑在 SSH 连接之外。ssh 只是远程操控 tmux 的工具，连接断了，tmux 还在。</p><p>tmux 里几个基础概念：</p><table tabindex="0"><thead><tr><th>概念</th><th>是什么</th><th>可以类比</th></tr></thead><tbody><tr><td>session</td><td>一个独立的 tmux 工作区</td><td>一个项目或一次变更操作</td></tr><tr><td>window</td><td>session 里的标签页</td><td>浏览器的一个标签页，每个里面跑着不同的终端</td></tr><tr><td>pane</td><td>window 里的分屏</td><td>一个窗口里切成上下或左右两块，可以同时看两样东西</td></tr><tr><td>prefix</td><td>tmux 的快捷键前缀</td><td>默认是 <code>Ctrl+b</code>，告诉 tmux &quot;下一个按键是给我的指令&quot;</td></tr></tbody></table><p>tmux 对运维人员来说，最核心的功能不是分屏——是会话持久化。生产机器上跑升级、迁移、批量脚本之类的事情，在 tmux 里面执行，至少不用怕断网。</p><h2 id="二、安装和启动" tabindex="-1">二、安装和启动 <a class="header-anchor" href="#二、安装和启动" aria-label="Permalink to &quot;二、安装和启动&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RHEL / CentOS / Rocky</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tmux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Debian / Ubuntu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tmux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>查看版本确认装上了：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -V</span></span></code></pre></div><p>创建一个命名会话：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span></span></code></pre></div><p><code>-s</code> 给会话起个名字。tmux 默认会分配数字编号（0、1、2），多个会话同时存在的时候，数字根本判断不了哪个是生产变更、哪个是临时排查。起名字是个很小的习惯，但出了事要恢复会话时，&quot;prod-change&quot;比&quot;2&quot;好用得多。</p><p>列出所有会话：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><p>连接到已有会话：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attach</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span></span></code></pre></div><p>从会话里暂时退出（detach），回普通 shell：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ctrl+b  再按 d</span></span></code></pre></div><p>detach 之后 tmux 里面的程序继续跑，不会被关掉。这和按 <code>Ctrl+d</code> 或输入 <code>exit</code> 不一样——那些是真退出 shell，tmux 窗口会被关闭。</p><h2 id="三、session-管理" tabindex="-1">三、session 管理 <a class="header-anchor" href="#三、session-管理" aria-label="Permalink to &quot;三、session 管理&quot;">​</a></h2><p>session 是工作区。开始一项变更时新建一个 session，做完后关掉。</p><table tabindex="0"><thead><tr><th>操作</th><th>命令</th></tr></thead><tbody><tr><td>新建会话</td><td><code>tmux new -s ops</code></td></tr><tr><td>查看所有会话</td><td><code>tmux ls</code></td></tr><tr><td>进入已有会话</td><td><code>tmux attach -t ops</code></td></tr><tr><td>重命名会话</td><td><code>tmux rename-session -t ops deploy</code></td></tr><tr><td>删除会话</td><td><code>tmux kill-session -t deploy</code></td></tr></tbody></table><p>在 tmux 里用快捷键操作 session：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>作用</th></tr></thead><tbody><tr><td><code>Ctrl+b d</code></td><td>detach——暂时离开，保留会话里的一切</td></tr><tr><td><code>Ctrl+b $</code></td><td>重命名当前 session</td></tr><tr><td><code>Ctrl+b s</code></td><td>列出所有 session，用方向键选一个切换进去</td></tr></tbody></table><p>一段典型的用法：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prod-change</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 执行变更命令</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./deploy.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 下班了，关笔记本回家</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 先 detach：Ctrl+b 再按 d</span></span></code></pre></div><p>家里 ssh 回服务器：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attach</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prod-change</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看到的是 deploy.sh 的完整输出，包括你离开后跑出来的部分</span></span></code></pre></div><p>如果 <code>tmux attach</code> 时报这个：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sessions should be nested with care, unset $TMUX to force</span></span></code></pre></div><p>意思是当前 shell 已经在另一个 tmux 会话里了。tmux 套 tmux 可以跑，但是快捷键会绕（外层的 <code>Ctrl+b</code> 被外层 tmux 吃掉，里层接收不到）。检查下当前是不是在 tmux 里：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TMUX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 有值说明当前已经在 tmux 里</span></span></code></pre></div><p>确认是不是已经在 tmux 里很重要，否则会误敲很多命令到错的位置。</p><h2 id="四、window-管理" tabindex="-1">四、window 管理 <a class="header-anchor" href="#四、window-管理" aria-label="Permalink to &quot;四、window 管理&quot;">​</a></h2><p>window 是 session 里面的标签页。一个 session 可以放多个 window，每个做不同的事：</p><table tabindex="0"><thead><tr><th>window</th><th>用途</th></tr></thead><tbody><tr><td><code>0: shell</code></td><td>执行命令</td></tr><tr><td><code>1: log</code></td><td>看日志</td></tr><tr><td><code>2: db</code></td><td>数据库连接</td></tr><tr><td><code>3: deploy</code></td><td>部署脚本</td></tr></tbody></table><p>快捷键：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>作用</th></tr></thead><tbody><tr><td><code>Ctrl+b c</code></td><td>新建一个 window</td></tr><tr><td><code>Ctrl+b ,</code></td><td>重命名当前 window</td></tr><tr><td><code>Ctrl+b n</code></td><td>切到下一个 window</td></tr><tr><td><code>Ctrl+b p</code></td><td>切到上一个 window</td></tr><tr><td><code>Ctrl+b 0</code> 到 <code>9</code></td><td>直接跳到指定编号的 window</td></tr><tr><td><code>Ctrl+b &amp;</code></td><td>关闭当前 window（会确认一次）</td></tr></tbody></table><p>命令行创建 window 也可以：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new-window</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new-window</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span></span></code></pre></div><p><code>-n</code> 指定窗口名字。排查问题时把窗口名改成 <code>log</code>、<code>tcpdump</code>、<code>app-status</code> 这种短名，比默认的 <code>bash</code> 直观很多。</p><h2 id="五、pane-分屏" tabindex="-1">五、pane 分屏 <a class="header-anchor" href="#五、pane-分屏" aria-label="Permalink to &quot;五、pane 分屏&quot;">​</a></h2><p>pane 是在同一个 window 里把屏幕切成几块。同时看日志和执行命令的时候很好用。</p><table tabindex="0"><thead><tr><th>快捷键</th><th>作用</th></tr></thead><tbody><tr><td><code>Ctrl+b %</code></td><td>左右分屏（竖线切）</td></tr><tr><td><code>Ctrl+b &quot;</code></td><td>上下分屏（横线切）</td></tr><tr><td><code>Ctrl+b 方向键</code></td><td>在分屏之间移动光标</td></tr><tr><td><code>Ctrl+b x</code></td><td>关闭当前所在的 pane</td></tr><tr><td><code>Ctrl+b z</code></td><td>当前 pane 最大化/还原</td></tr><tr><td><code>Ctrl+b 空格</code></td><td>循环切换预设布局（水平、垂直、平铺）</td></tr></tbody></table><p>命令行分屏：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> split-window</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 左右分屏</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> split-window</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 上下分屏</span></span></code></pre></div><p>一个常见的排查场景，上面看日志、下面敲请求：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 上面一个 pane：持续看日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 下面一个 pane：反复请求接口</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;curl -fsS http://127.0.0.1/healthz || echo failed&#39;</span></span></code></pre></div><p><code>watch -n 2</code> 每隔 2 秒循环执行一次命令。<code>curl -fsS</code> 是做健康检查常用的参数：<code>-f</code> 让 HTTP 错误（4xx/5xx）返回非 0 退出码；<code>-s</code> 静默不输出进度条；<code>-S</code> 搭配 <code>-s</code> 时让错误信息仍然显示。</p><p>分屏超过 4 个之后可读性明显下降——字太小、线太多、找焦点也慢。这时候多开个 window 比继续切分更合理。</p><h2 id="六、复制模式和滚动" tabindex="-1">六、复制模式和滚动 <a class="header-anchor" href="#六、复制模式和滚动" aria-label="Permalink to &quot;六、复制模式和滚动&quot;">​</a></h2><p>tmux 里面鼠标滚轮不一定会滚终端的输出历史。翻看之前的输出用&quot;复制模式&quot;。</p><p>进入复制模式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ctrl+b  [</span></span></code></pre></div><p>进去后可以用键盘上下翻、PageUp/PageDown 翻页、<code>/</code> 搜索。看完按 <code>q</code> 退出。</p><p>开启鼠标支持后，鼠标滚轮可以直接翻历史，拖拽可以选 pane 边界：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mouse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span></code></pre></div><p>这句话只对当前 tmux server 生效。想每次打开 tmux 都自动开启，写到 <code>~/.tmux.conf</code>：</p><div class="language-tmux vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tmux</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set -g mouse on</span></span>
<span class="line"><span>set -g history-limit 50000</span></span></code></pre></div><p><code>history-limit</code> 是每个 pane 能保存的历史行数，默认是 2000 行。看大量日志的时候 2000 行根本不够，可以适当调大。受限于 tmux server 的内存，几十万行还 ok，但每个 pane 都极度调大时要看在内存上的开销。</p><p>配置写完后加载：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> source-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.tmux.conf</span></span></code></pre></div><h2 id="七、长任务放在-tmux-里" tabindex="-1">七、长任务放在 tmux 里 <a class="header-anchor" href="#七、长任务放在-tmux-里" aria-label="Permalink to &quot;七、长任务放在 tmux 里&quot;">​</a></h2><p>适合放进 tmux 的任务：</p><table tabindex="0"><thead><tr><th>场景</th><th>原因</th></tr></thead><tbody><tr><td>数据迁移</td><td>时间长，不能因为 SSH 断开就退出</td></tr><tr><td>应用发布</td><td>需要边执行边看日志、边调整</td></tr><tr><td>批量巡检</td><td>多轮命令，结果保留在 pane 里回头翻</td></tr><tr><td>抓包</td><td><code>tcpdump</code> 可能跑很久，中途断开不能丢</td></tr><tr><td>数据库备份</td><td>任务长，失败后要看现场输出定位原因</td></tr></tbody></table><p>放到 tmux 里执行的备份例子：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backup</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /backup/mysql</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysqldump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --single-transaction</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --routines</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --triggers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    app_db</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /backup/mysql/app_db-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%F</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.sql</span></span></code></pre></div><p><code>--single-transaction</code> 在整个备份过程中保持同一个事务视图，适合 InnoDB，能减少锁表影响。<code>--routines</code> 和 <code>--triggers</code> 带上存储过程和触发器，不然恢复时这些对象就没了。</p><p>长任务的输出保留很重要。只靠 tmux 滚动缓冲区不够稳——缓冲区被新输出冲掉也正常，而且你连回来之前跑了什么也看不到。用 <code>tee</code> 同时显示和存档：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./deploy.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%F-%H%M%S</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.log</span></span></code></pre></div><p><code>2&gt;&amp;1</code> 把 stderr 合并到 stdout 后才进管道，<code>tee</code> 把流分成两份——一份继续打到终端，一份写入文件。这样即使 tmux 的滚动历史已经覆盖了，日志文件里还能找到完整输出。</p><h2 id="八、断线恢复" tabindex="-1">八、断线恢复 <a class="header-anchor" href="#八、断线恢复" aria-label="Permalink to &quot;八、断线恢复&quot;">​</a></h2><p>SSH 意外断开，重新登录服务器后：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                           # 看有哪些会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attach</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 恢复</span></span></code></pre></div><p>如果 attach 时报错说会话已被另一个客户端占用——可能是之前的连接还没被超时踢掉：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attach</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span></span></code></pre></div><p><code>-d</code> 把那个客户端 detach 掉，然后自己接管。通常是自己断线的残留连接，但多人共用同一个系统用户（比如都登 root）时，<code>-d</code> 会把别人正在操作的界面清掉。这个场景下用 <code>tmux list-clients -t ops</code> 先看一眼有谁连着。</p><p>会话名忘了用 <code>tmux ls</code> 列出所有的：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ops: 3 windows (created Thu May 21 10:00:00 2026) [120x35]</span></span></code></pre></div><p>输出里 <code>ops</code> 是会话名，<code>3 windows</code> 表示这 session 里有 3 个窗口，<code>120x35</code> 是创建时的终端尺寸。</p><p>如果 <code>tmux ls</code> 返回这个：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>no server running on /tmp/tmux-1000/default</span></span></code></pre></div><p>意思是当前用户名下没有任何活着的 tmux 会话。需要留意操作者的身份：root 创建的 tmux，普通用户是看不到的；普通用户创建的 tmux，切到 root 后也访问不到，因为 tmux server 的 socket 文件位于各用户的临时目录下。</p><h2 id="九、screen-老环境里的备选" tabindex="-1">九、screen：老环境里的备选 <a class="header-anchor" href="#九、screen-老环境里的备选" aria-label="Permalink to &quot;九、screen：老环境里的备选&quot;">​</a></h2><p>有些老系统上没装 tmux，但预装了 screen。screen 也能实现会话持久化。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> screen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> screen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">screen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># detach（离开但保留）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Ctrl+a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  再按</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> d</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">screen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ls</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 恢复会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">screen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span></span></code></pre></div><p>screen 的 prefix 是 <code>Ctrl+a</code> 而不是 <code>Ctrl+b</code>，其他概念差不多。screen 能解决问题，但 window/pane 管理、配置体验、社区生态这几个方面，tmux 都更完善。新环境能用 tmux 就直接用 tmux。</p><h2 id="十、一份简单的-tmux-conf" tabindex="-1">十、一份简单的 ~/.tmux.conf <a class="header-anchor" href="#十、一份简单的-tmux-conf" aria-label="Permalink to &quot;十、一份简单的 ~/.tmux.conf&quot;">​</a></h2><p>服务器上的 tmux 配置越精简越好——它是救场工具，不是日常开发环境：</p><div class="language-tmux vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tmux</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 开启鼠标支持：滚轮翻历史、点击切 pane</span></span>
<span class="line"><span>set -g mouse on</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 滚动缓冲区行数，排查日志时够翻一阵</span></span>
<span class="line"><span>set -g history-limit 50000</span></span>
<span class="line"><span></span></span>
<span class="line"><span># window 编号从 1 开始</span></span>
<span class="line"><span>set -g base-index 1</span></span>
<span class="line"><span>setw -g pane-base-index 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 状态栏刷新间隔</span></span>
<span class="line"><span>set -g status-interval 5</span></span></code></pre></div><p><code>base-index 1</code> 让窗口从 1 开始编号，和键盘数字行对齐。<code>pane-base-index 1</code> 同理，pane 编号也从 1 开始。</p><p>服务器上 tmux 不适合堆插件和复杂配置。插件依赖 tmux 版本、依赖网络安装、依赖本地文件系统——在陌生机器和应急场景下这些不确定因素都可能失效。朴素配置在任何一台服务器上都能直接工作。</p><h2 id="十一、速查" tabindex="-1">十一、速查 <a class="header-anchor" href="#十一、速查" aria-label="Permalink to &quot;十一、速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>命令或快捷键</th></tr></thead><tbody><tr><td>新建会话</td><td><code>tmux new -s ops</code></td></tr><tr><td>查看会话</td><td><code>tmux ls</code></td></tr><tr><td>恢复会话</td><td><code>tmux attach -t ops</code></td></tr><tr><td>强制接管</td><td><code>tmux attach -d -t ops</code></td></tr><tr><td>离开但保留</td><td><code>Ctrl+b d</code></td></tr><tr><td>新建 window</td><td><code>Ctrl+b c</code></td></tr><tr><td>重命名 window</td><td><code>Ctrl+b ,</code></td></tr><tr><td>左右分屏</td><td><code>Ctrl+b %</code></td></tr><tr><td>上下分屏</td><td><code>Ctrl+b &quot;</code></td></tr><tr><td>关闭 pane</td><td><code>Ctrl+b x</code></td></tr><tr><td>最大化/还原 pane</td><td><code>Ctrl+b z</code></td></tr><tr><td>进复制模式</td><td><code>Ctrl+b [</code></td></tr><tr><td>关闭会话</td><td><code>tmux kill-session -t ops</code></td></tr></tbody></table>`,98)])])}const g=t(n,[["render",p]]);export{r as __pageData,g as default};
